// Auto-generated: embedded fonts for the student report PDF.
// Fredoka (cover) and Quicksand (content), static Regular + SemiBold instances.
import type jsPDF from "jspdf";

const FredokaRegular = "";

const FredokaBold = "";

const QuicksandRegular = "";

const QuicksandBold = "";

let registered = false;

export const registerReportFonts = (doc: jsPDF) => {
  if (registered) {
    // VFS is per-document in some setups; re-add to be safe.
  }
  doc.addFileToVFS("Fredoka-Regular.ttf", FredokaRegular);
  doc.addFont("Fredoka-Regular.ttf", "Fredoka", "normal");
  doc.addFileToVFS("Fredoka-Bold.ttf", FredokaBold);
  doc.addFont("Fredoka-Bold.ttf", "Fredoka", "bold");

  doc.addFileToVFS("Quicksand-Regular.ttf", QuicksandRegular);
  doc.addFont("Quicksand-Regular.ttf", "Quicksand", "normal");
  doc.addFileToVFS("Quicksand-Bold.ttf", QuicksandBold);
  doc.addFont("Quicksand-Bold.ttf", "Quicksand", "bold");
  registered = true;
};
